interface Article {
  title: string
  link: string
  author: string
  description: string
}

interface ArticleListProps {
  articles: Article[]
  isLoading: boolean
}

export function ArticleList({ articles, isLoading }: ArticleListProps) {
  if (isLoading) {
    return <div>\u52A0\u8F7D\u4E2D...</div>
  }

  return (
    <div className="space-y-4">
      {articles.map((article, index) => (
        <article key={index} className="border rounded-lg p-4">
          <h2 className="text-xl font-bold">
            <a
              href={article.link}
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-500 hover:underline"
            >
              {article.title}
            </a>
          </h2>
          <p className="text-gray-600 mt-1">\u4F5C\u8005\uFF1A{article.author}</p>
          <p className="text-gray-700 mt-2">{article.description}</p>
        </article>
      ))}
    </div>
