`,(0,r.jsxDEV)(n.pre,{children:(0,r.jsxDEV)(n.code,{className:"language-typescript",children:`// src/hooks/useArticles.ts
import { useState, useEffect } from 'react'

export function useArticles(tag: string) {
  const [articles, setArticles] = useState([])
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState(null)

  const fetchArticles = async (page = 1) => {
    setIsLoading(true)
    setError(null)

    try {
      const response = await fetch(
        \`/api/juejin?tag=\${encodeURIComponent(tag)}&page=\${page}\`
      )
      const data = await response.json()

      if (!response.ok) throw new Error(data.error)

      setArticles(data.articles)
    } catch (err) {
      setError(err.message)
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    if (tag) {
      fetchArticles()
    }
  }, [tag])

  return { articles, isLoading, error, fetchArticles }
}
